INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES ("ＨＰ吸収ダウン", 10040906, "バトル開始時、すべてのキャラのＨＰ吸収をダウンさせる。", 4100409, 9);
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES ("光属性ボーナス特大アップ", 10041001, "光属性のキャラが４体以上編成されているとき、キャラの属性ボーナスが強化される。光属性以外の属性ボーナスを無効化する。", 4100410, 15);
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES ("ダメージ減衰", 10041002, "すべてのモンスターが一度の行動で受けるダメージ値を減衰させる。ダメージ値が上昇するほど減衰率も上昇する。", 4100410, 18);
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES ("物理防御力（ダウン不可）アップ", 10041003, "バトル開始時、すべてのモンスターの物理防御力をアップさせる。この効果は物理防御力ダウンの影響を受けない。", 4100410, "boss_def_lower_limit");
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES ("魔法防御力（ダウン不可）アップ", 10041004, "バトル開始時、すべてのモンスターの魔法防御力をアップさせる。この効果は魔法防御力ダウンの影響を受けない。", 4100410, "boss_magic_def_lower_limit");
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES ("ＴＰダウンカット", 10041005, "バトル開始時、すべてのモンスターがＴＰダウン\n75％カット状態になる。", 4100410, "boss_tp_down_cut");
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES ("ＴＰ上昇ダウン", 10041006, "バトル開始時、すべてのキャラのＴＰ上昇をダウンさせる。", 4100410, 3);
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES ("ＨＰ吸収ダウン", 10041007, "バトル開始時、すべてのキャラのＨＰ吸収をダウンさせる。", 4100410, 9);
